import React from 'react';
import { usePinInput } from '../hooks/usePinInput';
import { PinDots } from './PinDots';
import { Keypad } from './Keypad';
import { SuccessOverlay } from './SuccessOverlay';
import styles from './PinScreen.module.css';

// ── Logo: swap this src with your actual asset path ──────────────────────────
// Place your logo in /public/logo.png  →  src="/logo.png"
// Or import it:  import logo from '../assets/logo.png'
// -----------------------------------------------------------------------------
const LOGO_SRC = process.env.PUBLIC_URL + '/logo.png';

export function PinScreen() {
  const { digits, status, shake, handleKey, handleDelete, reset, remaining } =
    usePinInput();

  const isError   = status === 'error';
  const isSuccess = status === 'success';

  return (
    <div className={`${styles.root} ${isError ? styles.errorFlash : ''}`}>

      {/* Background decoration */}
      <div className={styles.bgAccent} />

      <main className={styles.card}>

        {/* Logo */}
        <div className={styles.logoWrap}>
          <img
            src={LOGO_SRC}
            alt="ArenaPlus Sportsbook"
            className={styles.logo}
            draggable={false}
          />
        </div>

        {/* Heading */}
        <div className={styles.heading}>
          <h1 className={styles.title}>GUESS THE CODE</h1>
          <p className={styles.subtitle}>
            {isError ? 'Incorrect PIN' : 'You only have 1 attempt'}
          </p>
        </div>

        {/* PIN Dots */}
        <PinDots digits={digits} status={status} shake={shake} />

        {/* Keypad */}
        <Keypad
          onKey={handleKey}
          onDelete={handleDelete}
          disabled={isSuccess}
        />

      </main>

      {/* Success overlay */}
      <SuccessOverlay show={isSuccess} onReset={reset} />
    </div>
  );
}
